const resp = $input.item.json;
const label = $('Search Queries').item.json.label;
return { json: { ...resp, label } };

const out = [];
for (const inputItem of $input.all()) {
  const results = inputItem.json.organic_results || [];
  const label = inputItem.json.label || 'serp';
  const projectLinks = results.filter(r => {
    const url = r.link || '';
    return !url.includes('/profil/') && !url.includes('/freelancer/');
  });
  for (const r of projectLinks.slice(0, 15)) {
    out.push({ json: { result: r, label } });
  }
}
return out;

const item = $input.item.json;
const r = item.result || {};
const label = item.label || 'serp';

// employment job boards vs freelance platforms — label prefix decides job_type
const EMPLOYMENT_LABELS = ['jisw-', 'studysmart-', 'hokify-', 'remote3-', 'ba-', 'gjobs-'];
const jobType = EMPLOYMENT_LABELS.some(p => label.startsWith(p)) ? 'employment' : 'freelance';
const isPraktikum = label.includes('praktikum') || label.includes('junior') || label.startsWith('ba-');

const title = r.title || '';
const sourceUrl = r.link || '';
const snippet = r.snippet || '';
const richSnippet = (r.rich_snippet && JSON.stringify(r.rich_snippet)) || '';

const rawText = [
  `Titel: ${title}`,
  `URL: ${sourceUrl}`,
  '',
  snippet,
  richSnippet
].filter(Boolean).join('\n').substring(0, 8000);

return {
  json: {
    normalized_input: {
      input_source: 'scraped',
      source_detail: 'gewerbe_scraped',
      job_type: jobType,
      email_account_id: null,
      email_address: null,
      email_provider: null,
      subject: title,
      date: null,
      raw_text: rawText,
      raw_meta: {
        url: sourceUrl,
        label,
        platform: 'google-serp'
      },
      filter_context: isPraktikum
        ? 'PRAKTIKUM/JUNIOR FILTER: This listing comes from a Praktikum/Werkstudent/Junior search. Set is_job_related=TRUE and action=create_job for ANY internship, working-student, trainee or junior role in IT, Software, Data, AI, KI, Digitalisierung or Automatisierung. Only set is_job_related=FALSE for clearly non-tech roles (Pflege, Bau, Gastro, Logistik, pure Marketing/Sales). Seniority intern/junior is EXPECTED here - do NOT apply the senior-exclusion or 5-years-experience red flags, do NOT cap relevance_score for onsite (Praktikum may be local).'
        : 'GEWERBE FILTER: Set is_job_related=FALSE unless project requires Python, n8n, AI, LLM, FastAPI, Docker, or Automation. EXCLUDE: SAP, Golang, Java, Kotlin, Android, iOS, C#, .NET, PHP, Ruby, Payroll, Buchhaltung, HR/Recruiting, pure PM roles without tech. Priority: Python+n8n+AI=high, Python+automation=medium.'
    }
  }
};

const body = $input.item.json;
let jobEvent;
try {
  let raw = (body.choices[0].message.content || '').trim();
  raw = raw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
  raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  jobEvent = JSON.parse(raw);
} catch (err) {
  throw new Error('LLM returned invalid JSON: ' + String(body?.choices?.[0]?.message?.content || '').substring(0, 300));
}

if (typeof jobEvent.is_job_related !== 'boolean') {
  throw new Error('Parse error: is_job_related must be boolean, got: ' + typeof jobEvent.is_job_related);
}
if (typeof jobEvent.injection_suspected !== 'boolean') jobEvent.injection_suspected = false;

const ALLOWED_ACTIONS = ['create_job','update_stage','add_interview','add_deadline','log_only','flag_error','ignore'];
if (!ALLOWED_ACTIONS.includes(jobEvent.action)) {
  throw new Error('Parse error: invalid action value: ' + String(jobEvent.action));
}

if (jobEvent.company_id && !/^[a-z0-9][a-z0-9-]*[a-z0-9]$/.test(jobEvent.company_id)) {
  jobEvent.company_id = jobEvent.company_id.toLowerCase().replace(/[^a-z0-9-]/g, '-').replace(/--+/g, '-').replace(/^-|-$/g, '');
}

if (!Array.isArray(jobEvent.tech_stack))      jobEvent.tech_stack = [];
if (!Array.isArray(jobEvent.key_requirements)) jobEvent.key_requirements = [];

const JOB_RELATED_CATEGORIES = ['job_posting','hr_invite','interview_invite','test_task','offer','rejection','follow_up','platform_notification','manual_note'];
if (JOB_RELATED_CATEGORIES.includes(jobEvent.category)) jobEvent.is_job_related = true;

jobEvent.is_job_related_str = jobEvent.is_job_related ? 'yes' : 'no';

return { json: { job_event: jobEvent } };

/* ============================================================
   Prepare DB Params -- Gewerbe Flow
   job_type = 'freelance'
   input_source: scraped, no email fields
   ============================================================ */

const e  = $input.item.json.job_event;
const ni = $('Normalize Item').item.json.normalized_input;
const rawText  = ni.raw_text;
const sourceUrl = (ni.raw_meta && ni.raw_meta.url) || null;

function sql(v)  { if (v === null || v === undefined) return 'NULL'; return "'" + String(v).replace(/'/g, "''") + "'"; }
function num(v)  { if (v === null || v === undefined) return 'NULL'; const n = parseFloat(v); return isNaN(n) ? 'NULL' : String(n); }
function bool(v) { return v === true ? 'TRUE' : 'FALSE'; }
function dt(v)   { return v ? "'" + String(v).replace(/'/g, "''") + "'" : 'NULL'; }
function en(v,t) { return v ? "'" + String(v).replace(/'/g, "''") + "'::" + t : 'NULL'; }
function arr(vals) {
  if (!vals || vals.length === 0) return "'{}'";
  const parts = vals.map(v => '"' + String(v).replace(/\\/g,'\\\\').replace(/"/g,'\\"') + '"');
  return "'" + '{' + parts.join(',') + '}' + "'";
}
function jsonb(v) {
  if (!v) return "'{}'::jsonb";
  return "'" + JSON.stringify(v).replace(/'/g, "''") + "'::jsonb";
}

function normWorkMode(v) {
  if (!v) return null;
  const s = String(v).toLowerCase().replace(/[-\s]/g, '_');
  const map = {
    on_site: 'onsite', onsite: 'onsite', in_office: 'onsite', office: 'onsite', vor_ort: 'onsite',
    full_remote: 'remote', fully_remote: 'remote', remote: 'remote', homeoffice: 'remote', home_office: 'remote',
    hybrid: 'hybrid', partially_remote: 'hybrid', teilweise_remote: 'hybrid'
  };
  return map[s] || null;
}
function normSeniority(v) {
  if (!v) return null;
  const s = String(v).toLowerCase().replace(/[-\s]/g, '_');
  const map = {
    intern: 'intern', internship: 'intern', praktikum: 'intern',
    junior: 'junior', jr: 'junior',
    middle: 'middle', mid: 'middle', medior: 'middle', intermediate: 'middle',
    senior: 'senior', sr: 'senior',
    lead: 'lead', tech_lead: 'lead', team_lead: 'lead',
    principal: 'principal', staff: 'principal', architect: 'principal'
  };
  return map[s] || null;
}


const finalSourceUrl = sourceUrl || e.source_url || null;

return {
  json: {
    job_event: e,
    db: {
      company_id_sql:           sql(e.company_id           || 'unknown'),
      company_name_sql:         sql(e.company_name         || 'Unknown Company'),
      employer_id_sql:          sql(e.employer_id),
      employer_name_sql:        sql(e.employer_name),
      job_id_fuzzy_sql:         sql(e.job_id_fuzzy         || 'unknown__unknown__unknown'),
      job_title_sql:            sql(e.job_title),
      location_sql:             sql(e.location),
      job_thread_key_sql:       sql(e.job_thread_key),
      seniority_sql:            en(normSeniority(e.seniority),             'seniority_enum'),
      work_mode_sql:            en(normWorkMode(e.work_mode),             'work_mode_enum'),
      work_mode_raw_sql:        sql(e.work_mode_raw),
      working_hours_sql:        sql(e.working_hours),
      salary_currency_sql:      sql(e.salary_currency),
      salary_min_sql:           num(e.salary_min),
      salary_max_sql:           num(e.salary_max),
      salary_period_sql:        (()=>{const m={monthly:'monthly',annual:'annual',yearly:'annual',hourly:'hourly'};const s=e.salary_period?m[String(e.salary_period).toLowerCase()]:null;return s?en(s,'salary_period_enum'):'NULL';})(),
      tech_stack_sql:           arr(e.tech_stack),
      key_requirements_sql:     arr(e.key_requirements),
      current_stage_sql:        en(e.stage || 'discovered', 'job_stage_enum'),
      priority_sql:             (()=>{const vp=['high','medium','low'];const s=e.priority?String(e.priority).toLowerCase().trim():null;return s&&vp.includes(s)?en(s,'priority_enum'):'NULL';})(),
      priority_level_sql:       num(e.priority_level),
      interview_date_sql:       dt(e.interview_date),
      response_deadline_sql:    dt(e.response_deadline),
      application_deadline_sql: dt(e.application_deadline),
      has_had_call_sql:         bool(e.has_had_call),
      call_count_sql:           String(e.call_count || 0),
      last_call_date_sql:       dt(e.last_call_date),
      source_url_sql:           sql(finalSourceUrl),
      source_input_sql:         en('scraped',               'input_source_enum'),
      job_type_sql:             sql(ni.job_type === 'employment' ? 'employment' : 'freelance'),
      summary_sql:              sql(e.summary),
      category_sql:             (()=>{const V=['hr_invite','interview_invite','test_task','offer','rejection','follow_up','job_posting','newsletter','platform_notification','manual_note','other'];const s=e.category?String(e.category).toLowerCase():null;return V.includes(s)?en(s,'job_category_enum'):en('other','job_category_enum');})(),
      action_sql:               sql(e.action),
      is_job_related_sql:       bool(e.is_job_related),
      call_platform_sql:        (()=>{const V=['zoom','teams','google_meet','phone','in_person','other'];const s=e.call_platform?String(e.call_platform).toLowerCase():null;return V.includes(s)?en(s,'call_platform_enum'):'NULL';})(),
      call_platform_raw_sql:    sql(e.call_platform_raw),
      raw_text_sql:             sql(rawText),
      parsed_json_sql:          jsonb(e),
      sender_risk_level_sql:    sql('unknown'),
      sender_risk_signals_sql:  arr([]),
      contact_email_sql:        sql((() => { const EMAIL_REGEX = /[\w\.\-\+]+@[\w\.\-]+\.[a-zA-Z]{2,}/g; const NOREPLY_RE = /noreply|no[-_]reply|donotreply|mailer|bounce|unsubscribe|newsletter|notification|info@|hallo@|kontakt@|support@|service@|hello@|sbv|betriebsrat|datenschutz/i; const allEmails = (rawText || '').match(EMAIL_REGEX) || []; return allEmails.find(em => !NOREPLY_RE.test(em)) || null; })())
    }
  }
};

// ============================================================
// Prepare Calendar Data - Gewerbe / KI Automation
// Builds a structured project card for Google Calendar.
// Color = relevance tier: green (hot) / yellow (medium) / graphite (low)
// ============================================================

const e  = $('Parse LLM Response').item.json.job_event;
const ni = $('Normalize Item').item.json.normalized_input;
const db = $input.item.json;

const relevance = parseInt(e.relevance_score || 0);

// --- Color tier ---
// 2 = Sage (green)   ? hot lead ?80
// 5 = Banana (yellow)? interesting 50-79
// 8 = Graphite (grey)? low <50
const colorId = relevance >= 80 ? '2' : relevance >= 50 ? '5' : '8';

// --- Rate / budget ---
let rateStr = '';
if (e.salary_min) {
  const period = e.salary_period === 'hourly'  ? '/h'
               : e.salary_period === 'daily'   ? '/d'
               : e.salary_period === 'monthly' ? '/mo'
               : e.salary_period === 'project' ? ' Projekt'
               : '';
  const cur = e.salary_currency || 'EUR';
  rateStr = ` | ${e.salary_min}${e.salary_max ? '-' + e.salary_max : ''}${cur}${period}`;
}

// --- Event title ---
const calSummary = '\uDD27 '
  + (e.job_title || 'Projekt')
  + ' @ '
  + (e.company_name || '?')
  + rateStr;

// --- Dates ---
const todayISO = new Date().toISOString().split('T')[0];
const calStart = e.application_deadline
  ? e.application_deadline.substring(0, 10)
  : e.response_deadline
  ? e.response_deadline.substring(0, 10)
  : todayISO;
const calEnd = calStart; // all-day event

// --- Tech stack ---
const techStr = Array.isArray(e.tech_stack) && e.tech_stack.length
  ? e.tech_stack.slice(0, 8).join(' � ')
  : null;

// --- Location ---
const locParts = [e.location, e.work_mode ? e.work_mode.replace('_', ' ') : null].filter(Boolean);
const locStr = locParts.length ? locParts.join(' | ') : null;

// --- Salary ---
let salaryStr = null;
if (e.salary_min) {
  const period = e.salary_period === 'hourly'  ? 'pro Stunde'
               : e.salary_period === 'daily'   ? 'pro Tag'
               : e.salary_period === 'monthly' ? 'pro Monat'
               : e.salary_period === 'project' ? 'Projektbudget'
               : '';
  const cur = e.salary_currency || 'EUR';
  salaryStr = `${e.salary_min}${e.salary_max ? '-' + e.salary_max : ''} ${cur} ${period}`.trim();
}

// --- Key requirements ---
const reqStr = Array.isArray(e.key_requirements) && e.key_requirements.length
  ? e.key_requirements.slice(0, 4).join(' � ')
  : null;

// --- Deadline label ---
const deadlineLabel = e.application_deadline
  ? e.application_deadline.substring(0, 10)
  : e.response_deadline
  ? e.response_deadline.substring(0, 10)
  : '-';

// --- Source URL ---
const sourceUrl = (ni.raw_meta && ni.raw_meta.url) || '';
const platform  = (ni.raw_meta && ni.raw_meta.platform) || ni.raw_meta && ni.raw_meta.label || '?';

// --- Today label ---
const today = new Date().toLocaleDateString('de-DE', {
  day: '2-digit', month: '2-digit', year: 'numeric'
});

// --- Stage label ---
const stageLabel = (db.stage || 'discovered').toUpperCase();

// --- Relevance bar (10 blocks) ---
const filledBlocks = Math.round(relevance / 10);
const bar = '\u2588'.repeat(filledBlocks) + '\u2591'.repeat(10 - filledBlocks);

// --- Build description ---
const lines = [
  '\u2550'.repeat(30),
  '\uDF10 KI AUTOMATION GEWERBE-RADAR',
  '\u2550'.repeat(30),
  '',
  '\uDFE2 Auftraggeber:  ' + (e.company_name || '?'),
];
if (techStr)    lines.push('\uDD27 Stack:         ' + techStr);
if (reqStr)     lines.push('\uDCCB Anforderungen: ' + reqStr);
if (locStr)     lines.push('\uDCCD Ort:           ' + locStr);
if (salaryStr)  lines.push('\uDCB0 Verg\u00FCtung:    ' + salaryStr);
lines.push('');
lines.push('\uDCC8 Relevanz: [' + bar + '] ' + relevance + '/100');
lines.push('');
if (e.summary) {
  lines.push('\uDCAC ZUSAMMENFASSUNG');
  lines.push(e.summary);
  lines.push('');
}
lines.push('\u2500'.repeat(30));
if (sourceUrl)      lines.push('\uDD17 Quelle:        ' + sourceUrl);
lines.push('\uDFF7\uFE0F Plattform:     ' + platform);
lines.push('\uDCC5 Erfasst:       ' + today);
lines.push('\u23F0 Deadline:      ' + deadlineLabel);
lines.push('\uDEA6 Status:        ' + stageLabel);
lines.push('');
lines.push('\u2500'.repeat(30));
lines.push('JobRadar Gewerbe - KI Automation Intelligence Hub');

const calDescription = lines.join('\n');

return {
  json: {
    // pass through DB fields for IF: priority node
    job_id:      db.job_id,
    stage:       db.stage,
    priority:    db.priority,
    summary:     db.summary,
    // calendar params
    calSummary,
    calStart,
    calEnd,
    calColorId:  colorId,
    calDescription
  }
};

const out = [];
for (const item of $input.all()) {
  const e = item.json.job_event;
  const deadline = (e && (e.application_deadline || e.response_deadline)) || null;
  if (deadline) {
    const d = new Date(deadline);
    if (!isNaN(d.getTime()) && d < new Date()) continue;
  }
  out.push(item);
}
return out;

const jobs = $input.item.json.jobs || [];
const stripHtml = s => (s || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

const listed = jobs
  .filter(j => j.isListed !== false)
  .sort((a, b) => new Date(b.publishedAt) - new Date(a.publishedAt))
  .slice(0, 30);

return listed.map(j => {
  const comp = j.compensation?.compensationTierSummary || '';
  const snippet = [
    `Ort: ${j.location || 'unbekannt'}${j.isRemote ? ' (Remote)' : ''}`,
    `Typ: ${j.employmentType || ''}`,
    comp ? `Verguetung: ${comp}` : '',
    stripHtml(j.descriptionHtml).substring(0, 1500)
  ].filter(Boolean).join('\n');

  return { json: { result: { title: `${j.title} @ 10x.team`, link: j.jobUrl, snippet }, label: 'ashby-10xteam' } };
});

const BASE = 'https://rest.arbeitsagentur.de/jobboerse/jobsuche-service/pc/v4/jobs';
const QUERIES = [
  { url: BASE + '?was=' + encodeURIComponent('KI Automatisierung') + '&angebotsart=34&size=25', label: 'ba-praktikum' },
  { url: BASE + '?was=' + encodeURIComponent('Automatisierung Python') + '&angebotsart=1&arbeitszeit=ho&size=25', label: 'ba-remote' },
  { url: BASE + '?was=' + encodeURIComponent('KI Automatisierung') + '&angebotsart=1&arbeitszeit=ho&size=25', label: 'ba-remote' },
];
return QUERIES.map(q => ({ json: q }));

const queries = $('BA: Suchanfragen').all();
const out = [];
const inputs = $input.all();
for (let idx = 0; idx < inputs.length; idx++) {
  const item = inputs[idx];
  const p = item.pairedItem;
  const qIdx = (typeof p === 'number') ? p : (p && typeof p.item === 'number' ? p.item : idx);
  const label = (queries[qIdx] && queries[qIdx].json.label) || 'ba';
  const jobs = item.json.stellenangebote || [];
  for (const j of jobs.slice(0, 25)) {
    if (!j.refnr) continue;
    out.push({ json: {
      refnr: j.refnr,
      refnr_b64: Buffer.from(String(j.refnr)).toString('base64'),
      titel: j.titel || '',
      arbeitgeber: j.arbeitgeber || '',
      ort: (j.arbeitsort && (j.arbeitsort.ort || j.arbeitsort.region)) || '',
      label
    }});
  }
}
return out;

const d = $input.item.json || {};
const meta = $('BA: Flatten').item.json;
const link = 'https://www.arbeitsagentur.de/jobsuche/jobdetail/' + meta.refnr;

const blob = JSON.stringify(d).replace(/\\[ntr]/g, ' ');
const mails = blob.match(/[a-zA-Z0-9._%+-]+@[a-zA-Z0-9-]+(\.[a-zA-Z0-9-]+)*\.[a-zA-Z]{2,}/g) || [];
const BAD = /(arbeitsagentur|noreply|no-reply|example\.|sbv|betriebsrat|datenschutz|widerruf)/i;
const email = [...new Set(mails.map(m => m.toLowerCase()))].filter(m => !BAD.test(m))[0] || null;

const beschreibung = (d.stellenbeschreibung || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const snippet = [
  'Arbeitgeber: ' + (meta.arbeitgeber || d.arbeitgeber || 'unbekannt'),
  'Ort: ' + (meta.ort || 'unbekannt'),
  meta.label === 'ba-praktikum' ? 'Art: Praktikum/Trainee/Werkstudent' : 'Art: Festanstellung (Homeoffice-Filter)',
  email ? 'Bewerbung per E-Mail: ' + email : '',
  beschreibung.substring(0, 2500)
].filter(Boolean).join('\n');

return { json: { result: { title: (meta.titel || 'Unbekannt') + (meta.arbeitgeber ? ' @ ' + meta.arbeitgeber : ''), link, snippet }, label: meta.label } };

parameters.query:
SELECT item->'result' AS result, item->>'label' AS label
FROM jsonb_array_elements($1::jsonb) AS item
WHERE NOT EXISTS (
  SELECT 1 FROM jobs WHERE source_url = item->'result'->>'link'
);

parameters.jsCode:
const QUERIES = [
  { q: 'Praktikum KI', label: 'gjobs-praktikum' },
  { q: 'Praktikum Automatisierung Python', label: 'gjobs-praktikum' },
  { q: 'Junior KI Automatisierung remote', label: 'gjobs-junior' },
];
return QUERIES.map(q => ({ json: q }));

const queries = $('GJobs: Suchanfragen').all();
const out = [];
const inputs = $input.all();
for (let idx = 0; idx < inputs.length; idx++) {
  const item = inputs[idx];
  const p = item.pairedItem;
  const qIdx = (typeof p === 'number') ? p : (p && typeof p.item === 'number' ? p.item : idx);
  const label = (queries[qIdx] && queries[qIdx].json.label) || 'gjobs';
  const jobs = item.json.jobs_results || [];
  for (const j of jobs.slice(0, 15)) {
    const applyLink = (j.apply_options && j.apply_options[0] && j.apply_options[0].link) || j.share_link || null;
    if (!applyLink) continue;
    const ext = j.detected_extensions || {};
    const snippet = [
      'Arbeitgeber: ' + (j.company_name || 'unbekannt'),
      'Ort: ' + (j.location || 'unbekannt'),
      ext.schedule_type ? 'Art: ' + ext.schedule_type : '',
      j.via ? 'Via: ' + j.via : '',
      (j.description || '').substring(0, 2500)
    ].filter(Boolean).join('\n');
    out.push({ json: { result: { title: (j.title || '') + (j.company_name ? ' @ ' + j.company_name : ''), link: applyLink, snippet }, label } });
  }
}
return out;
